class AwsService(val region: String) {
  private val credentials = new EnvironmentVariableCredentialsProvider().getCredentials
  private val s3Client = new AmazonS3Client(credentials)
  private val sqsClient = new AmazonSQSClient(credentials)

  def getS3Object(bucketName: String, key: String): S3Object = {
